/usr/bin/python3 - <<'PY'
import json
import uuid
import urllib.request
import urllib.error
from pathlib import Path
from datetime import datetime

QDRANT_URL = "http://qdrant:6333"
OLLAMA_URL = "http://ollama:11434"
EMBED_MODEL = "nomic-embed-text"

SOURCE_CANDIDATES = [
    "/data/rag_manual/catalog_questions_v2_fixed.json",
    "/data/rag_manual/catalog_questions_v2.json",
    "/data/rag_manual/catalog_questions.json"
]

COLLECTION = "tfm_rag_manual_agent"


def request_json(method, url, payload=None, timeout=180):
    data = None
    headers = {"Content-Type": "application/json"}

    if payload is not None:
        data = json.dumps(payload, ensure_ascii=False).encode("utf-8")

    req = urllib.request.Request(
        url,
        data=data,
        headers=headers,
        method=method
    )

    try:
        with urllib.request.urlopen(req, timeout=timeout) as response:
            raw = response.read().decode("utf-8")
            return json.loads(raw) if raw else {}
    except urllib.error.HTTPError as e:
        body = e.read().decode("utf-8", errors="replace")
        raise Exception(f"HTTP {e.code} en {url}: {body}")


def qdrant(method, path, payload=None):
    return request_json(
        method,
        QDRANT_URL.rstrip("/") + path,
        payload=payload,
        timeout=180
    )


def ollama_embedding(text):
    payload = {
        "model": EMBED_MODEL,
        "prompt": text
    }

    response = request_json(
        "POST",
        OLLAMA_URL.rstrip("/") + "/api/embeddings",
        payload=payload,
        timeout=240
    )

    emb = response.get("embedding")

    if not emb:
        raise Exception(f"Ollama no devolvió embedding para texto: {text[:200]}")

    return emb


def first_non_empty(*values):
    for value in values:
        if value is None:
            continue

        text = str(value).strip()

        if text and text.lower() not in ["none", "null", "undefined"]:
            return text

    return ""


def load_catalog():
    for candidate in SOURCE_CANDIDATES:
        path = Path(candidate)

        if path.exists():
            data = json.loads(path.read_text(encoding="utf-8"))
            print(f"Usando catálogo: {path}", flush=True)
            return data

    raise Exception("No se encontró ningún catalog_questions*.json en /data/rag_manual")


def normalize_questions(data):
    if isinstance(data, list):
        return data

    if isinstance(data, dict):
        for key in ["questions", "items", "catalog", "records", "data"]:
            if isinstance(data.get(key), list):
                return data[key]

    raise Exception(
        "Formato de catálogo no reconocido. "
        "Se esperaba lista o dict con questions/items/catalog/records/data."
    )


def unwrap_catalog_record(record):
    """
    Tu catálogo tiene esta forma:
    {
      "id": "RAG-Q_001",
      "qdrant_point_id": "...",
      "vector_text": "...",
      "payload": {
        "question_id": "Q_001",
        ...
      }
    }

    Esta función lo convierte en un único dict plano con question_id en raíz.
    """

    if not isinstance(record, dict):
        return {}

    payload = record.get("payload")

    if isinstance(payload, dict):
        q = dict(payload)

        # Conservamos campos útiles de la raíz.
        q["_catalog_record_id"] = record.get("id")
        q["_qdrant_point_id_original"] = record.get("qdrant_point_id")

        if record.get("vector_text"):
            q["_original_vector_text"] = record.get("vector_text")

        if not q.get("chunk_id") and record.get("id"):
            q["chunk_id"] = record.get("id")

        if not q.get("logical_id") and record.get("id"):
            q["logical_id"] = record.get("id")

        return q

    return dict(record)


def make_agent_page_content(q):
    qid = first_non_empty(q.get("question_id"), q.get("id"), q.get("logical_id"))
    question_text = first_non_empty(q.get("question_text"), q.get("question"), q.get("text"))
    requisito = first_non_empty(q.get("requisito"))
    dimension = first_non_empty(q.get("dimension"))
    bloque = first_non_empty(q.get("bloque"))
    apartado = first_non_empty(q.get("apartado"))

    control_id = first_non_empty(q.get("control_id"))
    control_text = first_non_empty(q.get("control_text"))
    incumplimiento = first_non_empty(q.get("incumplimiento_identificado"))
    controles = first_non_empty(q.get("controles_asociados"))

    risk_id = first_non_empty(q.get("risk_id"))
    risk_name = first_non_empty(q.get("risk_name"))
    risk_description = first_non_empty(q.get("risk_description"))

    severity_logic = first_non_empty(q.get("severity_logic"), q.get("conditional_severity_logic"))
    evaluation_group = first_non_empty(q.get("evaluation_group"))

    conditional_rules = q.get("conditional_rules") or []
    if isinstance(conditional_rules, list):
        conditional_rules_text = "\n".join(f"- {x}" for x in conditional_rules if str(x).strip())
    else:
        conditional_rules_text = str(conditional_rules)

    raw_observations = first_non_empty(q.get("raw_observations"))
    mitigation = first_non_empty(q.get("mitigation"))

    severity_by_tier = q.get("severity_by_tier") or {}
    severity_by_tier_text = json.dumps(severity_by_tier, ensure_ascii=False)

    depends_on = q.get("depends_on_questions") or []
    depends_on_text = ", ".join(depends_on) if isinstance(depends_on, list) else str(depends_on)

    exact_token = f"EXACT_QUESTION_ID_{qid}"

    page_content = f"""
{exact_token}
{exact_token}
{exact_token}

QUESTION_ID: {qid}
PREGUNTA: {qid}
ID PREGUNTA: {qid}
Texto de la pregunta: {question_text}

Dimensión: {dimension}
Bloque: {bloque}
Apartado: {apartado}
Requisito: {requisito}

Control ID: {control_id}
Control: {control_text}
Incumplimiento identificado: {incumplimiento}
Controles asociados: {controles}

Riesgo ID: {risk_id}
Riesgo: {risk_name}
Descripción del riesgo: {risk_description}

Severity logic: {severity_logic}
Evaluation group: {evaluation_group}
Severity by tier: {severity_by_tier_text}
Depends on questions: {depends_on_text}

Reglas condicionales:
{conditional_rules_text}

Observaciones:
{raw_observations}

Mitigación:
{mitigation}

Instrucción para agente:
Esta ficha corresponde exclusivamente a la pregunta {qid}. No debe usarse para evaluar otras preguntas.
Si el agente está evaluando una pregunta distinta de {qid}, debe descartar esta ficha.
""".strip()

    return page_content


def make_payload(q, page_content):
    qid = first_non_empty(q.get("question_id"), q.get("id"), q.get("logical_id"))

    metadata = {
        "doc_type": first_non_empty(q.get("doc_type"), "risk_catalog_question"),
        "question_id": qid,
        "question_number": q.get("question_number"),
        "chunk_id": q.get("chunk_id"),
        "logical_id": first_non_empty(q.get("logical_id"), q.get("chunk_id"), f"RAG-{qid}"),
        "dimension": q.get("dimension"),
        "bloque": q.get("bloque"),
        "apartado": q.get("apartado"),
        "requisito": q.get("requisito"),
        "risk_id": q.get("risk_id"),
        "risk_name": q.get("risk_name"),
        "control_id": q.get("control_id"),
        "control_ids": q.get("control_ids"),
        "evaluation_group": q.get("evaluation_group"),
        "severity_logic": q.get("severity_logic"),
        "depends_on_questions": q.get("depends_on_questions"),
        "source_file": q.get("source_file"),
        "source_sheet": q.get("source_sheet"),
        "source_row": q.get("source_row")
    }

    metadata = {
        k: v for k, v in metadata.items()
        if v not in [None, "", []]
    }

    payload = dict(q)

    payload.update({
        "pageContent": page_content,
        "text": page_content,
        "content": page_content,
        "vector_text": page_content,
        "metadata": metadata,
        "agent_rag_ready": True,
        "agent_rag_indexed_at": datetime.now().isoformat(timespec="seconds")
    })

    return payload


catalog = load_catalog()
raw_records = normalize_questions(catalog)

questions = []

for record in raw_records:
    q = unwrap_catalog_record(record)

    qid = first_non_empty(
        q.get("question_id"),
        q.get("id"),
        q.get("logical_id"),
        q.get("chunk_id")
    )

    if not qid:
        continue

    if not qid.startswith("Q_"):
        continue

    questions.append(q)

if not questions:
    sample = raw_records[0] if raw_records else {}
    raise Exception(
        "No se encontraron preguntas Q_XXX válidas en el catálogo. "
        "Ejemplo primer registro: "
        + json.dumps(sample, ensure_ascii=False)[:1500]
    )

print(f"Registros fuente: {len(raw_records)}", flush=True)
print(f"Preguntas válidas detectadas: {len(questions)}", flush=True)

test_embedding = ollama_embedding("test")
vector_size = len(test_embedding)

print(f"Dimensión embedding: {vector_size}", flush=True)

try:
    qdrant("DELETE", f"/collections/{COLLECTION}")
    print(f"Colección anterior eliminada: {COLLECTION}", flush=True)
except Exception as e:
    print(f"No se pudo eliminar colección anterior o no existía: {e}", flush=True)

qdrant(
    "PUT",
    f"/collections/{COLLECTION}",
    {
        "vectors": {
            "size": vector_size,
            "distance": "Cosine"
        }
    }
)

print(f"Colección creada: {COLLECTION}", flush=True)

points = []
indexed = 0

for q in questions:
    qid = first_non_empty(q.get("question_id"), q.get("id"), q.get("logical_id"))
    page_content = make_agent_page_content(q)
    payload = make_payload(q, page_content)
    embedding = ollama_embedding(page_content)

    point_id = str(uuid.uuid5(uuid.NAMESPACE_DNS, f"{COLLECTION}:{qid}"))

    points.append({
        "id": point_id,
        "vector": embedding,
        "payload": payload
    })

    indexed += 1

    if len(points) >= 20:
        qdrant(
            "PUT",
            f"/collections/{COLLECTION}/points?wait=true",
            {
                "points": points
            }
        )

        print(f"Indexados {indexed}/{len(questions)}", flush=True)
        points = []

if points:
    qdrant(
        "PUT",
        f"/collections/{COLLECTION}/points?wait=true",
        {
            "points": points
        }
    )

    print(f"Indexados {indexed}/{len(questions)}", flush=True)

print(json.dumps({
    "status": "OK",
    "collection": COLLECTION,
    "source_records": len(raw_records),
    "indexed_questions": indexed,
    "embedding_model": EMBED_MODEL,
    "vector_size": vector_size
}, ensure_ascii=False, indent=2))
